import React from 'react';
import { FiMessageCircle } from 'react-icons/fi';

function WhatsAppButton() {
  const handleClick = () => {
    window.open('https://wa.me/+918870839663?text=', '_blank', 'noopener,noreferrer');
  };

  return (
    <button
      type="button"
      onClick={handleClick}
      className="fixed bottom-6 right-24 z-40 rounded-full p-4 shadow-lg bg-[#25D366] text-white hover:opacity-90 transition-opacity"
      aria-label="Chat on WhatsApp"
    >
      <FiMessageCircle size={22} />
    </button>
  );
}

export default WhatsAppButton;
